// FILE: packages/app/src/lib/actions/observeChapterBoundary.ts

interface ChapterBoundaryParams {
    getRoot: () => HTMLElement | null;
    onChapterChange: (chapterId: string) => void;
}

let sharedObserver: IntersectionObserver | null = null;
let sharedCallback: ((chapterId: string) => void) | null = null;
let sharedRoot: HTMLElement | null = null;
let observedNodes: Set<HTMLElement> = new Set();

function ensureObserver(params: ChapterBoundaryParams): void {
    const root = params.getRoot();
    if (sharedObserver && root === sharedRoot) return;

    if (sharedObserver) {
        sharedObserver.disconnect();
    }

    sharedRoot = root;
    sharedCallback = params.onChapterChange;

    if (!root) {
        sharedObserver = null;
        return;
    }

    sharedObserver = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting && entry.intersectionRatio >= 0.5) {
                    const chId = (entry.target as HTMLElement).dataset.chapterId;
                    if (chId) sharedCallback?.(chId);
                }
            }
        },
        { threshold: 0.5, root },
    );

    for (const node of observedNodes) {
        sharedObserver.observe(node);
    }
}

export function observeChapterBoundary(
    node: HTMLElement,
    params: ChapterBoundaryParams,
) {
    observedNodes.add(node);
    ensureObserver(params);
    sharedObserver?.observe(node);

    return {
        destroy() {
            observedNodes.delete(node);
            sharedObserver?.unobserve(node);
        },
    };
}

export function disconnectChapterObserver() {
    sharedObserver?.disconnect();
    sharedObserver = null;
    sharedCallback = null;
    sharedRoot = null;
    observedNodes.clear();
}

// FILE: packages/app/src/lib/actions/observePageImages.ts

import type { ReaderMemoryManager } from '$lib/services/ReaderMemoryManager.js';

interface PageImageParams {
    memory: ReaderMemoryManager;
    getRoot: () => HTMLElement | null;
    chapterId: string;
    pageIndex: number;
    url: string;
}

let sharedObserver: IntersectionObserver | null = null;
let sharedMemory: ReaderMemoryManager | null = null;
let pendingNodes: HTMLElement[] = [];

function ensureObserver(memory: ReaderMemoryManager, getRoot: () => HTMLElement | null): boolean {
    if (sharedObserver && sharedMemory === memory) return true;

    const root = getRoot();
    if (!root) return false;

    sharedObserver?.disconnect();
    sharedMemory = memory;
    sharedObserver = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    const data = sharedMemory?.pageDataMap.get(entry.target as HTMLElement);
                    if (data) {
                        const img = entry.target.querySelector('img');
                        if (img && !img.src) {
                            sharedMemory?.loadImage(data.url, data.key, img);
                        }
                    }
                }
            }
        },
        { rootMargin: '500% 0px', root },
    );

    for (const pending of pendingNodes) {
        sharedObserver.observe(pending);
    }
    pendingNodes = [];

    return true;
}

export function observePageImages(
    node: HTMLElement,
    getParams: () => PageImageParams,
) {
    const { memory, getRoot, chapterId, pageIndex, url } = getParams();
    memory.registerPage(node, chapterId, pageIndex, url);

    if (ensureObserver(memory, getRoot)) {
        sharedObserver!.observe(node);
    } else {
        pendingNodes.push(node);
    }

    return {
        destroy() {
            sharedObserver?.unobserve(node);
            const idx = pendingNodes.indexOf(node);
            if (idx >= 0) pendingNodes.splice(idx, 1);
            memory.unregisterPage(node);
        },
    };
}

export function flushPageObserver(memory: ReaderMemoryManager, getRoot: () => HTMLElement | null) {
    if (pendingNodes.length > 0) {
        ensureObserver(memory, getRoot);
    }
}

export function disconnectPageObserver() {
    sharedObserver?.disconnect();
    sharedObserver = null;
    sharedMemory = null;
    pendingNodes = [];
}

// FILE: packages/app/src/lib/actions/sentinel.ts
export interface SentinelParams {
    getRoot: () => HTMLElement | null;
    rootMargin: string;
    onIntersect: () => void;
    disabled?: boolean;
    generation?: number;
}

export function sentinel(node: HTMLElement, params: SentinelParams) {
    let observer: IntersectionObserver | null = null;
    let currentGeneration = params.generation ?? 0;
    let firedSinceCreate = false;

    function create() {
        observer?.disconnect();
        firedSinceCreate = false;
        const root = params.getRoot();
        if (!root) return;
        observer = new IntersectionObserver(
            (entries) => {
                for (const entry of entries) {
                    if (entry.isIntersecting) {
                        firedSinceCreate = true;
                        params.onIntersect();
                    }
                }
            },
            { rootMargin: params.rootMargin, root },
        );
        observer.observe(node);
    }

    function scheduleHealthCheck() {
        requestAnimationFrame(() => {
            if (!observer || params.disabled || firedSinceCreate) return;
            const root = params.getRoot();
            if (!root || !node.isConnected) return;

            const rootRect = root.getBoundingClientRect();
            const nodeRect = node.getBoundingClientRect();
            const parts = params.rootMargin.trim().split(/\s+/);
            const bottomMarginStr = parts.length >= 3 ? parts[2] : parts[0];
            let extensionPx = 0;
            if (bottomMarginStr.endsWith('%')) {
                extensionPx = (parseFloat(bottomMarginStr) / 100) * rootRect.height;
            } else {
                extensionPx = parseFloat(bottomMarginStr) || 0;
            }

            if (nodeRect.top <= rootRect.bottom + extensionPx) {
                firedSinceCreate = true;
                params.onIntersect();
            }
        });
    }

    if (!params.disabled) {
        create();
        scheduleHealthCheck();
    }

    return {
        update(next: SentinelParams) {
            const prevGeneration = currentGeneration;
            params = next;
            currentGeneration = next.generation ?? 0;
            const generationChanged = currentGeneration !== prevGeneration;

            if (next.disabled) {
                if (observer) {
                    observer.disconnect();
                    observer = null;
                }
            } else if (!observer || generationChanged) {
                create();
                scheduleHealthCheck();
            }
        },
        destroy() {
            observer?.disconnect();
        },
    };
}

// FILE: packages/app/src/lib/actions/swipeBack.ts
import { appDimensions } from '$lib/state/appDimensions.js';
import { SWIPE_THRESHOLD, DEADZONE_RATIO, EDGE_ZONE_RATIO } from '../constants.js';

interface SwipeBackOptions {
    onClose: () => void;
    ui: { swipeProgress: number; isSwiping: boolean; swipeAnimating: boolean };
}

export function swipeBack(node: HTMLElement, options: SwipeBackOptions) {
    let tracking = false;
    let startX = 0;
    let startY = 0;
    let locked = false;
    let rejected = false;
    let lockDx = 0;
    let opts = options;

    function onStart(e: TouchEvent) {
        const touch = e.touches[0];
        const edgeZone = appDimensions.width * EDGE_ZONE_RATIO;
        if (touch.clientX <= edgeZone) {
            tracking = true;
            locked = false;
            rejected = false;
            lockDx = 0;
            startX = touch.clientX;
            startY = touch.clientY;
        }
    }

    function onMove(e: TouchEvent) {
        if (!tracking || rejected) return;

        const touch = e.touches[0];
        const dx = touch.clientX - startX;
        const dy = touch.clientY - startY;
        const appWidth = appDimensions.width;

        if (!locked) {
            const absDx = Math.abs(dx);
            const absDy = Math.abs(dy);
            const deadzone = appWidth * DEADZONE_RATIO;
            if (absDx < deadzone && absDy < deadzone) return;
            if (absDy > absDx) {
                rejected = true;
                tracking = false;
                return;
            }
            locked = true;
            lockDx = dx;
            opts.ui.isSwiping = true;
        }

        e.preventDefault();

        const travel = dx - lockDx;
        const maxTravel = appWidth - lockDx;
        opts.ui.swipeProgress = Math.max(0, Math.min(1, travel / maxTravel));
    }

    function onEnd() {
        if (!tracking || !locked) {
            tracking = false;
            return;
        }

        tracking = false;
        const progress = opts.ui.swipeProgress;

        opts.ui.swipeAnimating = true;

        if (progress > SWIPE_THRESHOLD) {
            opts.ui.swipeProgress = 1;
            setTimeout(() => {
                opts.ui.isSwiping = false;
                opts.ui.swipeAnimating = false;
                opts.ui.swipeProgress = 0;
                opts.onClose();
            }, 250);
        } else {
            opts.ui.swipeProgress = 0;
            setTimeout(() => {
                opts.ui.isSwiping = false;
                opts.ui.swipeAnimating = false;
            }, 250);
        }
    }

    node.addEventListener('touchstart', onStart, { passive: true });
    node.addEventListener('touchmove', onMove, { passive: false });
    node.addEventListener('touchend', onEnd, { passive: true });

    return {
        update(newOptions: SwipeBackOptions) {
            opts = newOptions;
        },
        destroy() {
            node.removeEventListener('touchstart', onStart);
            node.removeEventListener('touchmove', onMove);
            node.removeEventListener('touchend', onEnd);
        }
    };
}

// FILE: packages/app/src/lib/components/ChapterList.svelte
<script lang="ts">
    import { appState } from '$lib/state/index.svelte.js';
    import type { ChapterMeta } from '$lib/types.js';
    import FilterChip from './FilterChip.svelte';

    let { chapters }: { chapters: ChapterMeta[] } = $props();

    const mangaId = $derived(appState.manga.activeManga?.id ?? '');
    const gf = appState.groupFilter;
    const selectedGroups = $derived(appState.manga.selectedGroups);

    $effect(() => {
        mangaId;
        gf.showFiltered = false;
    });

    $effect(() => {
        const target = appState.manga.scrollTarget;
        if (!target) return;
        const container = document.getElementById('view-manga');
        const el = container?.querySelector(`[data-chapter-id="${CSS.escape(target.chapterId)}"]`);
        if (!container || !el) return;
        const elTop = (el as HTMLElement).offsetTop;
        const desiredScrollTop = elTop - target.ratio * container.clientHeight;
        container.scrollTop = Math.max(0, desiredScrollTop);
    });

    const hasFilteredChapters = $derived(
        gf.count > 0 && chapters.some(ch => gf.isFiltered(ch.groupId ?? ''))
    );

    const effectiveCount = $derived.by(() => {
        if (gf.showFiltered || gf.count === 0) return chapters.length;
        return chapters.filter(ch => !gf.isFiltered(ch.groupId ?? '')).length;
    });

    let pendingGroup = $state<{ id: string; name: string } | null>(null);

    function handleLongPressGroup(groupId: string, groupName: string) {
        if (pendingGroup?.id === groupId) {
            pendingGroup = null;
        } else {
            pendingGroup = { id: groupId, name: groupName };
        }
    }

    function confirmFilter() {
        if (!pendingGroup) return;
        const { id, name } = pendingGroup;
        if (gf.isFiltered(id)) {
            gf.remove(id);
            appState.toast.show(`Unblocked "${name}"`);
        } else {
            gf.add(id, name);
            appState.toast.show(`Blocked "${name}"`);
        }
        pendingGroup = null;
    }

    const groups = $derived.by(() => {
        const map = new Map<string, { id: string; name: string; count: number }>();
        for (const ch of chapters) {
            const gid = ch.groupId ?? '';
            const existing = map.get(gid);
            if (existing) {
                existing.count++;
            } else {
                map.set(gid, {
                    id: gid,
                    name: ch.groupName || 'No Group',
                    count: 1,
                });
            }
        }
        return [...map.values()].sort((a, b) => b.count - a.count);
    });

    const filtered = $derived(appState.manga.filteredChapters);

    type GapIndicator = { type: 'gap'; missing: number; from: number; to: number };
    type ListItem = { type: 'chapter'; chapter: ChapterMeta } | GapIndicator;

    const listItems = $derived.by((): ListItem[] => {
        const result: ListItem[] = [];
        for (let i = 0; i < filtered.length; i++) {
            result.push({ type: 'chapter', chapter: filtered[i] });
            if (i < filtered.length - 1) {
                const cur = Math.floor(filtered[i].number);
                const next = Math.floor(filtered[i + 1].number);
                const missing = cur - next - 1;
                if (missing > 0) {
                    result.push({ type: 'gap', missing, from: next + 1, to: cur - 1 });
                }
            }
        }
        if (filtered.length > 0) {
            const lowest = Math.floor(filtered[filtered.length - 1].number);
            if (lowest > 1) {
                const missing = lowest - 1;
                result.push({ type: 'gap', missing, from: 1, to: lowest - 1 });
            }
        }
        return result;
    });

    const currentProgress = $derived(appState.progress.get(mangaId));
    const currentChapterId = $derived(currentProgress?.chapterId ?? null);
    const progressPercent = $derived.by(() => {
        if (currentProgress?.pageIndex == null || !currentProgress?.pageCount) return 0;
        return Math.round(((currentProgress.pageIndex + 1) / currentProgress.pageCount) * 100);
    });

    function handleClick(chapter: ChapterMeta) {
        const manga = appState.manga.activeManga;
        if (!manga) return;

        const container = document.getElementById('view-manga');
        const el = container?.querySelector(`[data-chapter-id="${CSS.escape(chapter.id)}"]`);
        if (container && el) {
            const containerRect = container.getBoundingClientRect();
            const elRect = el.getBoundingClientRect();
            appState.manga.captureScrollAnchor(
                (elRect.top - containerRect.top) / containerRect.height
            );
        }

        appState.reader.openReader(manga, chapter);
    }

    function scrollIfCurrent(node: HTMLElement, isCurrent: boolean) {
        if (isCurrent) {
            requestAnimationFrame(() => {
                node.scrollIntoView({ block: 'center' });
            });
        }
        return {};
    }

    function formatDate(ts?: number): string {
        if (!ts) return '';
        const d = new Date(ts * 1000);
        const now = Date.now();
        const diff = now - d.getTime();
        const hours = Math.floor(diff / 3600000);
        if (hours < 1) return 'just now';
        if (hours < 24) return `${hours}h ago`;
        const days = Math.floor(hours / 24);
        if (days < 30) return `${days}d ago`;
        const months = Math.floor(days / 30);
        if (months < 12) return `${months}mo ago`;
        return `${Math.floor(months / 12)}y ago`;
    }

    function isChapterFiltered(ch: ChapterMeta): boolean {
        return gf.isFiltered(ch.groupId ?? '');
    }
</script>

<div class="chapter-filter">
    <FilterChip
        label={`All (${effectiveCount})`}
        active={selectedGroups.size === 0}
        onclick={() => appState.manga.selectAllGroups()}
    />
    {#each groups as group (group.id)}
        <FilterChip
            label={`${group.name} (${group.count})`}
            active={selectedGroups.has(group.id)}
            excluded={gf.isFiltered(group.id)}
            onclick={() => appState.manga.toggleGroup(group.id)}
            onlongpress={() => handleLongPressGroup(group.id, group.name)}
        />
    {/each}
    {#if hasFilteredChapters}
        <button
            class="show-filtered-btn"
            class:active={gf.showFiltered}
            onclick={() => gf.showFiltered = !gf.showFiltered}
        >{gf.showFiltered ? 'Hide filtered' : 'Show filtered'}</button>
    {/if}
    {#if pendingGroup}
        <div class="inline-confirm">
            <span class="inline-confirm-name">{pendingGroup.name}</span>
            <button class="inline-confirm-btn cancel" onclick={() => pendingGroup = null}>Cancel</button>
            <button
                class="inline-confirm-btn"
                class:block-btn={!gf.isFiltered(pendingGroup.id)}
                class:unblock-btn={gf.isFiltered(pendingGroup.id)}
                onclick={confirmFilter}
            >{gf.isFiltered(pendingGroup.id) ? 'Unblock' : 'Block'}</button>
        </div>
    {/if}
</div>

<div class="chapter-list">
    {#each listItems as item (item.type === 'chapter' ? item.chapter.id : `gap-${item.from}-${item.to}`)}
        {#if item.type === 'gap'}
            <div class="chapter-gap">
                {item.missing} chapter{item.missing > 1 ? 's' : ''} missing (Ch. {item.from}{item.from !== item.to ? ` – ${item.to}` : ''})
            </div>
        {:else}
            {@const chapter = item.chapter}
            {@const isCurrent = chapter.id === currentChapterId}
            <button
                class="chapter-item"
                class:chapter-current={isCurrent}
                class:chapter-filtered={gf.showFiltered && isChapterFiltered(chapter)}
                style={isCurrent && progressPercent > 0 ? `background: linear-gradient(to right, rgba(45, 212, 191, 0.55) ${progressPercent}%, #1a1a1a ${progressPercent}%)` : ''}
                data-chapter-id={chapter.id}
                use:scrollIfCurrent={isCurrent}
                onclick={() => handleClick(chapter)}
            >
                <span class="chapter-number">{chapter.number}</span>
                <span class="chapter-group">{chapter.groupName || 'No Group'}</span>
                {#if chapter.uploadedAt}
                    <span class="chapter-date">{formatDate(chapter.uploadedAt)}</span>
                {/if}
            </button>
        {/if}
    {/each}
</div>
