// FILE: packages/app/src/lib/components/FilterChip.svelte
<script lang="ts">
    let {
        label,
        active = false,
        included = false,
        excluded = false,
        onclick,
        onlongpress,
    }: {
        label: string;
        active?: boolean;
        included?: boolean;
        excluded?: boolean;
        onclick: () => void;
        onlongpress?: () => void;
    } = $props();

    let longPressTimer: ReturnType<typeof setTimeout> | null = null;
    let didLongPress = false;

    function handleTouchStart() {
        if (!onlongpress) return;
        didLongPress = false;
        longPressTimer = setTimeout(() => {
            didLongPress = true;
            onlongpress!();
        }, 500);
    }

    function clearTimer() {
        if (longPressTimer) {
            clearTimeout(longPressTimer);
            longPressTimer = null;
        }
    }

    function handleClick(e: MouseEvent) {
        if (didLongPress) {
            didLongPress = false;
            e.preventDefault();
            return;
        }
        onclick();
    }
</script>

<button
    class="filter-chip"
    class:active
    class:include={included}
    class:exclude={excluded}
    onclick={handleClick}
    ontouchstart={handleTouchStart}
    ontouchend={clearTimer}
    ontouchcancel={clearTimer}
    ontouchmove={clearTimer}
>{label}</button>

<style>
